    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<int> answer(n, -1);
        queue<pair<int, int>> redQ, blueQ;
        redQ.push({0, 0});
        blueQ.push({0, 1});
        while (!redQ.empty() || !blueQ.empty()) {
            if (!redQ.empty()) {
                auto [node, color] = redQ.front();
                redQ.pop();
                if (node == answer.size() - 1) {
                    continue;
                }
                for (auto [next, _] : redEdges) {
                    if (next == node) {
                        continue;
                    }
                    if (answer[next] == -1) {
                        answer[next] = color + 1;
                        blueQ.push({next, 1});
                    }
                }
            }
            if (!blueQ.empty()) {
